INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGHKXAPTDWFNDC9RKA6D9ZW', 'eid_seasonal_promotion', 'Eid Seasonal Promotion', '{"pattern_ulid": "01KSGHKXAPTDWFNDC9RKA6D9ZW", "pattern_name": "Eid Seasonal Promotion", "pattern_slug": "eid_seasonal_promotion", "schema_version": 1, "description": "Limited-time Eid festival food promotions featuring collaborative branded products with emphasis on exclusivity, premium ingredients, and festive timing urgency.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 2, "structural_recipe": "Create Eid-exclusive food promotion posts featuring: (1) Co-branded special edition product (e.g., meat boxes, seasonal items), (2) Arabic captions emphasizing limited availability and festive occasion, (3) Sensory language describing taste/quality (\u0645\u0630\u0627\u0642 \u063a\u0646\u064a\u060c \u064a\u0630\u0648\u0628\u060c \u0623\u0644\u0630), (4) Celebratory emojis (\ud83d\udd25\ud83d\ude0d\u2728\ud83d\udc9b), (5) Urgency framing (\u0641\u062a\u0631\u0629 \u0645\u062d\u062f\u0648\u062f\u0629\u060c \u0627\u0644\u062d\u0642 \u0639\u0644\u064a\u0647\u0627), (6) Product imagery showing premium presentation, (7) Call-to-action implying scarcity", "why_it_works": "Eid holds deep cultural and emotional significance in Saudi society as a major celebration. Limited-edition seasonal products trigger FOMO (fear of missing out) while the festive framing aligns consumption with cultural values of celebration and family gatherings. Collaborative branding adds prestige and social credibility.", "transplantation_caveats": ["Timing sensitivity: promotions must launch within appropriate Eid season windows to avoid cultural misalignment", "Scarcity claims must be authentic; false limited-availability messaging violates consumer trust in Gulf markets", "Product must be genuinely premium/special; ordinary offerings repackaged as Eid editions will backfire", "Avoid aggressive pricing during religious holidays as it conflicts with cultural values of generosity"], "applicable_chains": [], "avg_engagement_multiplier_observed": "0% high-eng (3 obs)", "cultural_constraints": ["Eid promotion timing must respect Islamic calendar dates", "Celebratory tone should feel authentic to Eid traditions, not exploitative", "Family/togetherness messaging resonates more than individual consumption"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T21:44:45Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 3}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGV7RCRMXR2RWD2V0D65VST', 'winter_drinks', 'Winter Drinks', '{"pattern_ulid": "01KSGV7RCRMXR2RWD2V0D65VST", "pattern_name": "Winter Drinks", "pattern_slug": "winter_drinks", "schema_version": 1, "description": "Seasonal beverage content showcasing warm winter drink offerings with cozy aesthetics and flavor pairings, targeting comfort-seeking Saudi consumers during cooler months.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "Feature close-up or lifestyle shots of hot seasonal beverages (hot chocolate, specialty lattes, warm drinks). Include dual flavor/variant presentation. Use warm color grading and cozy visual composition. Caption should highlight the seasonal nature, flavor combinations, and emotional connection to warmth/comfort. Include brand hashtags and local cultural references (#\u0645\u0646\u0646\u0627_\u0648\u064a\u0641\u0647\u0645_\u062c\u0648\u0646\u0627 style). Use coffee cup/beverage emojis and weather-related emojis (\u2744\ufe0f\u2615).", "why_it_works": "Saudi Arabia''s winter season creates natural seasonal demand for warm beverages. The pattern leverages nostalgia and comfort-seeking behavior during cooler months. Flavor pairing communication (\u0634\u0648\u0643\u0644\u064a\u062a + \u0645\u0627\u062a\u0634\u0627) creates perceived value and choice perception. Local cultural references build community connection and authenticity.", "transplantation_caveats": ["Seasonal relevance limited to winter months (November-March in Saudi Arabia)", "Requires localized flavor preferences and Arabic-language captions for authentic engagement", "Hot beverage culture less dominant than in Western markets; positioning should emphasize luxury/specialty rather than everyday habit"], "applicable_chains": [], "avg_engagement_multiplier_observed": "0% high-eng (1 obs)", "cultural_constraints": [], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-26T00:26:34Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 1}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGBTDTNSAZ71GCS0V82Q7M8', 'post_occasion_content', 'Post Occasion Content', '{"pattern_ulid": "01KSGBTDTNSAZ71GCS0V82Q7M8", "pattern_name": "Post Occasion Content", "pattern_slug": "post_occasion_content", "schema_version": 1, "description": "Content created and posted in direct response to cultural, religious, or celebratory occasions, capturing real-time engagement with significant moments.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "Post timely content tied to Islamic holidays, national celebrations, or cultural events (Eid, Ramadan, Saudi National Day). Show products/services in occasion context, use festive visuals, incorporate celebratory language and relevant hashtags. Post within 24 hours of occasion start. Include family/community themes and traditional elements.", "why_it_works": "Saudi audiences exhibit heightened emotional connection and consumption during occasions. Timely, culturally-relevant content demonstrates brand awareness of community values and creates urgency. Occasion-based content aligns with peak spending periods and community sentiment, driving authentic engagement through cultural resonance.", "transplantation_caveats": ["Timing must align precisely with occasion calendar to avoid appearing tone-deaf or late", "Content must respect religious significance\u2014avoid purely commercial framing for Islamic occasions", "Failure to acknowledge occasion appropriately can damage brand credibility in Saudi market", "Occasion content has shelf-life; relevance drops sharply post-occasion"], "applicable_chains": [], "avg_engagement_multiplier_observed": "100% high-eng (1 obs)", "cultural_constraints": ["Must respect Islamic calendar and religious observance protocols", "Content framing should balance celebration with cultural reverence", "Avoid Western-centric celebration frameworks"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T20:02:24Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 1}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGMBBGXGVTJ73F7SS7B4J0W', 'eid_campaign', 'Eid Campaign', '{"pattern_ulid": "01KSGMBBGXGVTJ73F7SS7B4J0W", "pattern_name": "Eid Campaign", "pattern_slug": "eid_campaign", "schema_version": 1, "description": "Limited-time Eid promotional campaign offering bundled food products with exclusive deals and festive messaging to drive holiday-season sales and emotional connection.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "Post features limited-time Eid bundle offer (main product + complementary item) with: festive emojis and Arabic greeting, clear value proposition (what''s included), urgency language (''\u0645\u062d\u062f\u0648\u062f''/''\u0627\u0644\u062d\u064a\u0646''), colloquial Saudi Arabic tone emphasizing family celebration aspect, call-to-action directing to order, visual focus on packaged product bundles showing quantity and appeal.", "why_it_works": "Eid is peak consumption period in Saudi culture with strong family gathering traditions. Limited-time offers create FOMO while bundling increases average order value. Arabic-language casual tone with family-centric messaging (''\u0648\u0646\u0627\u0633\u0629''/togetherness) triggers cultural resonance and holiday obligation to celebrate with quality food.", "transplantation_caveats": ["Timing must align with actual Eid dates\u2014premature or delayed campaigns lose relevance", "Bundle composition should reflect actual Saudi Eid dining preferences and family sizes", "Discount/offer must be genuinely limited or credibility damage occurs", "Pattern may not translate to non-Muslim markets or regions without similar holiday structures"], "applicable_chains": [], "avg_engagement_multiplier_observed": "0% high-eng (1 obs)", "cultural_constraints": ["Must use appropriate Islamic greeting conventions during Eid period", "Pricing and promotions should not appear exploitative of holiday spending", "Family/togetherness framing essential\u2014avoid individualistic messaging"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T22:32:30Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 1}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGK4YMKVRSSW26AM0RB0SHQ', 'international_womens_day', 'International Womens Day', '{"pattern_ulid": "01KSGK4YMKVRSSW26AM0RB0SHQ", "pattern_name": "International Womens Day", "pattern_slug": "international_womens_day", "schema_version": 1, "description": "Celebratory content honoring women''s achievements and empowerment on International Women''s Day, combining inspirational messaging with brand-specific offerings and calls for audience participation.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "Post celebratory carousel or single image featuring women-focused imagery. Lead with empowerment message in Arabic or English (or both). Include specific achievement or beauty affirmation relevant to brand. Add interactive CTA asking women to share their accomplishments or celebrate themselves. Mention limited-time branded product/offer tied to the occasion (e.g., special tumbler, exclusive item). Use relevant hashtags: #\u064a\u0648\u0645_\u0627\u0644\u0645\u0631\u0623\u0629 #\u064a\u0648\u0645_\u0627\u0644\u0645\u0631\u0623\u0629_\u0627\u0644\u0639\u0627\u0644\u0645\u064a and brand-specific tags. Maintain aspirational, inclusive tone.", "why_it_works": "Saudi audiences respond strongly to content celebrating women''s empowerment and societal progress, particularly during globally recognized occasions like International Women''s Day. The pattern combines cultural values (women''s achievements, family/community focus) with commercial incentive (limited-time products), creating dual emotional and transactional appeal. Interactive elements (asking women to share stories) drive engagement through participation and community building. Bilingual approach broadens reach across Arabic-first and English-fluent audiences.", "transplantation_caveats": ["Ensure messaging aligns with Saudi cultural values regarding women''s roles and achievements\u2014focus on professional, educational, and personal accomplishments rather than contentious social issues", "Avoid imagery or messaging that could be perceived as contradicting conservative cultural norms", "Limited-time offers must be clearly communicated to avoid perceived false advertising", "Hashtag selection matters: use established, locally-recognized women''s day hashtags to maximize discoverability"], "applicable_chains": [], "avg_engagement_multiplier_observed": "100% high-eng (2 obs)", "cultural_constraints": ["Content must celebrate women within culturally appropriate context of professional and personal achievement", "Avoid feminist framing that may alienate conservative segments of audience", "Ensure inclusivity across different female demographics (professionals, mothers, students, entrepreneurs)"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T22:10:39Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 2}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGHG7PM2GQMPF5S8JK72WXK', 'eid_promotion', 'Eid Promotion', '{"pattern_ulid": "01KSGHG7PM2GQMPF5S8JK72WXK", "pattern_name": "Eid Promotion", "pattern_slug": "eid_promotion", "schema_version": 1, "description": "F&B restaurants leverage Eid holiday timing with bundled meat + table setup offers, emphasizing value and convenience through playful Arabic copy and emojis.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 2, "structural_recipe": "1) Lead with rhetorical hook about Eid readiness (''\u062d\u062c\u0632\u062a \u0630\u0628\u064a\u062d\u0629 \u0627\u0644\u0639\u064a\u062f \u0648\u0644\u0627 \u0644\u0633\u0651\u0649\u061f''). 2) Highlight main offering (premium meat cut) + free bundled sides (table decoration, prepared dishes). 3) Use warm Arabic colloquial tone with family/gathering context. 4) Include 1-2 emojis (sheep \ud83d\udc11, orange heart \ud83e\udde1, sparkles \u2728). 5) Add soft CTA (\u0627\u062d\u062c\u0632/\u0627\u0644\u062d\u0642 \u0639\u0644\u0649 \u0627\u0644\u0639\u0631\u0636). 6) Close with branded hashtag (#\u0645\u0637\u0627\u0639\u0645_\u0627\u0644\u0631\u0648\u0645\u0627\u0646\u0633\u064a\u0629).", "why_it_works": "Eid is peak family gathering season in Saudi culture. This pattern addresses decision fatigue (pre-bundled offerings reduce planning burden) while signaling abundance and care through hospitality traditions. The ''meat + full setup'' framing speaks to traditional feast expectations, creating psychological permission to order premium. Playful tone + emojis humanize the restaurant and reduce purchase friction.", "transplantation_caveats": ["Timing-dependent: only effective 4-6 weeks before Eid al-Fitr/Adha", "Sheep emoji (\ud83d\udc11) carries cultural sensitivity in livestock context\u2014ensure tone remains celebratory, not transactional", "Free bundled services must be genuinely included; overclaiming damages trust in conservative Saudi market", "Requires inventory visibility; promote only when stock confirms delivery capacity"], "applicable_chains": [], "avg_engagement_multiplier_observed": "25% high-eng (4 obs)", "cultural_constraints": ["Halal certification assumed but never explicitly stated in captions\u2014trust is implicit", "Family-first framing essential; avoid luxury/individual indulgence angles", "Ramadan overlap periods require sensitivity; post timing affects reception"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T21:42:55Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 4}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGK6ZCV0GHWBWZZVMTQ77SR', 'winter_beverage_promotion', 'Winter Beverage Promotion', '{"pattern_ulid": "01KSGK6ZCV0GHWBWZZVMTQ77SR", "pattern_name": "Winter Beverage Promotion", "pattern_slug": "winter_beverage_promotion", "schema_version": 1, "description": "Seasonal winter beverage promotions that pair hot drinks with winter weather metaphors and colloquial Arabic wordplay to create relatable, humorous content for F&B brands.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "1) Feature a signature winter beverage (e.g., White Mocha) prominently in visual; 2) Use weather-related imagery (snow, cold symbols \u2744\ufe0f); 3) Craft caption using colloquial Saudi Arabic that connects the drink to winter relief/comfort; 4) Employ wordplay or rhyming phrases (e.g., ''\u0634\u062f\u0651\u0647\u0627/\u064a\u0644\u0637\u0651\u0641\u0647\u0627'' pattern); 5) Include branded hashtags (#\u0628\u0627\u0631\u0646\u0632) and relatable campaign tags (#\u0645\u0646\u0646\u0627_\u0648\u064a\u0641\u0647\u0645_\u062c\u0648\u0646\u0627); 6) Position drink as essential winter solution.", "why_it_works": "Saudi audiences respond to seasonal relevance and conversational Arabic that mirrors local dialect. The wordplay creates memorability and shareability. Positioning comfort beverages as winter essentials taps into practical need while the humor builds emotional connection and brand personality.", "transplantation_caveats": ["Wordplay effectiveness depends on fluent colloquial Saudi Arabic\u2014direct translation to other Gulf dialects may reduce impact", "Winter season relevance is limited to November-February; pattern has low applicability outside this window", "Reliance on specific brand hashtags means pattern portability requires equivalent campaign infrastructure"], "applicable_chains": [], "avg_engagement_multiplier_observed": "0% high-eng (2 obs)", "cultural_constraints": ["Must use colloquial Saudi Arabic (Najdi dialect preferred) rather than formal MSA for authenticity", "Beverage must align with halal and Islamic consumption norms (no alcohol)", "Seasonal timing critical\u2014off-season posting reduces relevance"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T22:12:38Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 2}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSHAC9G12RHCS9DKP34GF1DN', 'everyday_summer_fits', 'Everyday Summer Fits', '{"pattern_ulid": "01KSHAC9G12RHCS9DKP34GF1DN", "pattern_name": "Everyday Summer Fits", "pattern_slug": "everyday_summer_fits", "schema_version": 1, "description": "Modest summer wardrobing content showcasing practical, styled abayas and modest wear combinations with brand partnerships and styling advice for the Saudi summer season.", "observed_in_sectors": ["retail_lifestyle"], "observed_in_account_count": 1, "structural_recipe": "Post high-quality flat-lay or on-body styling photos of summer abayas paired with accessories. Caption should include: (1) styling context (e.g., ''perfect match for summer modest wardrobe''), (2) product tags and brand mentions via @ handles, (3) relevant hashtags covering modest fashion, summer looks, and wardrobe keywords. Use sun/warmth emojis and hand emojis to convey approachability. Structure as educational content that positions modest wear as fashionable and practical.", "why_it_works": "Saudi audiences value modest fashion guidance that balances cultural authenticity with contemporary styling. Brand collaborations add credibility and shopping intent. Positioning modest wear as intentional fashion rather than obligation resonates with younger demographics navigating tradition and modernity. Summer-specific content addresses seasonal wardrobing needs and drives seasonal purchasing cycles.", "transplantation_caveats": ["Modest wear framing essential\u2014avoid positioning as trend rather than cultural/religious practice", "Brand partnership authenticity critical; forced collaborations read as inauthentic", "Summer-specific insights must address actual climate challenges (heat, sun intensity) not just aesthetics", "Geographic limitation: content optimized for Saudi market; transplantation to non-Muslim majority markets requires recontextualization"], "applicable_chains": [], "avg_engagement_multiplier_observed": "0% high-eng (1 obs)", "cultural_constraints": ["Must maintain modest dress standards in all imagery", "Brand partnerships should align with halal/Islamic values where relevant", "Styling advice should reinforce cultural norms rather than challenge them"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-26T04:57:40Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:retail_lifestyle"}, "status": "evidence_based", "obs_usage_count": 1}'::jsonb, '["retail_lifestyle"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSD0A3B4C5D6E7F8G9H0J1K0', 'football_occasion_tie_in', 'Football Occasion Tie-In', '{"pattern_ulid": "01KSD0A3B4C5D6E7F8G9H0J1K0", "pattern_name": "Football Occasion Tie-In", "pattern_slug": "football_occasion_tie_in", "schema_version": 1, "description": "Content inserts the brand into a Saudi football cultural moment \u2014 Saudi Pro League matches, national team games, Roshn Saudi League fixtures, or major Arab football events. The brand becomes part of the viewing/gathering occasion.", "observed_in_sectors": ["f_and_b", "retail"], "observed_in_account_count": 2, "structural_recipe": "Post types: [Pre-match] ''\u0644\u064a\u0644\u0629 \u0627\u0644\u0645\u0628\u0627\u0631\u0627\u0629 \u0645\u0639\u0627\u0646\u0627'' + match viewing food/drink offer \u2014 [During match] real-time product CTA \u2014 [Post-match] result-acknowledgment with brand. Tone: passionate but not partisan (avoid supporting specific team unless brand has official partnership). Delivery + ordering CTAs perform well in this context.", "why_it_works": "Football occasions in Saudi Arabia generate extremely high-intensity social engagement \u2014 audiences are fully active on their phones before, during, and after matches. Brands that show up in this context authentically (not just slapping a ball logo on their product) become part of the cultural ritual. Match-day delivery offers and viewing party food content are high-conversion contexts.", "transplantation_caveats": ["Do not take partisan team positions unless the brand has official team partnership.", "Content must be timely \u2014 pre-match posts after kick-off are ignored.", "Delivery mechanics tied to football occasions have significantly higher conversion than general football content.", "Saudi national team games carry more cultural weight than club games \u2014 allocate proportionally."], "applicable_chains": ["all"], "avg_engagement_multiplier_observed": "0.6x-1.2x", "cultural_constraints": [], "provenance": {"source": "corpus_synthesis_474_obs \u2014 referenced in obs but previously undefined", "date_added": "2026-05-24T00:00:00Z", "confirmer": "corpus_mining_pass_phase3", "confidence": "experimental", "scope": "sector:f_and_b+sector:retail"}, "status": "evidence_based", "obs_usage_count": 2}'::jsonb, '["f_and_b", "retail"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
INSERT INTO account_patterns (pattern_ulid, pattern_slug, pattern_name, payload, observed_in_sectors, provenance) VALUES ('01KSGJJ31SRDEBCFCR86RYYAK2', 'ramadan_campaign', 'Ramadan Campaign', '{"pattern_ulid": "01KSGJJ31SRDEBCFCR86RYYAK2", "pattern_name": "Ramadan Campaign", "pattern_slug": "ramadan_campaign", "schema_version": 1, "description": "Interactive Ramadan-themed promotional campaigns combining product engagement with charitable giving and entertainment elements, using festive hashtags and community participation.", "observed_in_sectors": ["f_and_b"], "observed_in_account_count": 1, "structural_recipe": "Create multi-night interactive Ramadan campaigns featuring: (1) Product showcases with new menu items positioned as ''try and rate'', (2) Charitable tie-ins where purchases contribute to charity (e.g., ''\u0631\u064a\u0627\u0644 \u0645\u0646 \u0643\u0644 \u0643\u0648\u0628''), (3) Entertaining game elements (\u0641\u0648\u0627\u0632\u064a\u0631 - riddles/trivia), (4) Clear second-chance messaging for missed events, (5) Use branded hashtags (#\u0645\u0646\u0646\u0646\u0627_\u0648\u064a\u0641\u0647\u0645_\u062c\u0648\u0646\u0627 #\u0628\u0627\u0631\u0646\u0632 #\u0631\u0645\u0636\u0627\u0646) consistently, (6) Emojis for visual appeal (\ud83d\ude09 \u2728 \ud83d\udc9a \ud83c\udf19 \ud83d\udc40), (7) Direct calls-to-action encouraging participation and product testing.", "why_it_works": "Ramadan in Saudi culture emphasizes community, charity, and festive spirit. This pattern leverages: (1) Religious/cultural alignment through charitable giving component, (2) Entertainment and family engagement through interactive games, (3) FOMO recovery through ''second chance'' messaging building inclusivity, (4) Brand loyalty through repeated nightly engagement touchpoints, (5) Social proof through community participation and rating requests.", "transplantation_caveats": ["Requires authentic charitable partnership to avoid appearing exploitative of Islamic values", "Timing-sensitive: only effective during Ramadan period; outside Ramadan will feel out-of-context", "Hashtag authenticity matters\u2014forced Arabic hashtags without genuine local insight may backfire", "Must balance commercial intent with genuine community benefit perception", "Multi-night execution requires content calendar commitment; single posts underperform this pattern"], "applicable_chains": [], "avg_engagement_multiplier_observed": "33% high-engagement (3 observations)", "cultural_constraints": ["Content must respect Islamic principles and avoid anything contradicting Ramadan values", "Charitable component should not appear performative or superficial", "Entertainment elements (games, riddles) should be family-appropriate", "Timing consideration: avoid posting during prayer times, especially Maghrib"], "provenance": {"source": "cross_account_synthesis_2026 + benchmark_account observations", "date_added": "2026-05-25T22:00:52Z", "confirmer": "claude_code_extraction", "confidence": "inferred", "scope": "sector:f_and_b"}, "status": "evidence_based", "obs_usage_count": 3}'::jsonb, '["f_and_b"]'::jsonb, '{"source": "ogz-knowledge seed"}'::jsonb) ON CONFLICT (pattern_slug) DO NOTHING;
